diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..091249111881 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,6 +3345,99 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
+
+    // (ext i1 A) + (ext i1 B) == C --> boolean expression
+    // zext(i1) has values {0, 1}; sext(i1) has values {0, -1}.
+    // The sum can only take a few values; map eq/ne C to boolean logic.
+    {
+      Value *A, *B;
+      bool AIsSExt, BIsSExt;
+      // Try both operand orderings.
+      auto MatchExt = [&](Value *V, Value *&BoolVal, bool &IsSExt) {
+        if (match(V, m_ZExt(m_Value(BoolVal)))) {
+          IsSExt = false;
+          return BoolVal->getType()->isIntOrIntVectorTy(1);
+        }
+        if (match(V, m_SExt(m_Value(BoolVal)))) {
+          IsSExt = true;
+          return BoolVal->getType()->isIntOrIntVectorTy(1);
+        }
+        return false;
+      };
+      if ((MatchExt(BOp0, A, AIsSExt) && MatchExt(BOp1, B, BIsSExt)) ||
+          (MatchExt(BOp1, A, AIsSExt) && MatchExt(BOp0, B, BIsSExt))) {
+        int ValA = AIsSExt ? -1 : 1; // value when A is true
+        int ValB = BIsSExt ? -1 : 1; // value when B is true
+        int64_t CSign = C.getSExtValue();
+        Value *Result = nullptr;
+
+        if (isICMP_NE) {
+          // ne C is simply the negation of eq C.
+          // The sum can be: 0 (both false), ValB (A=0,B=1), ValA (A=1,B=0),
+          // ValA+ValB (both true).
+          // For eq C, the result is the disjunction of cases where sum == C.
+          // For ne C, it's the negation.
+          // We build the eq result and negate.
+          Value *EqResult = nullptr;
+          auto AddEqCase = [&](Value *Cond) {
+            if (!EqResult)
+              EqResult = Cond;
+            else
+              EqResult = Builder.CreateOr(EqResult, Cond);
+          };
+          // both false (sum == 0)
+          if (CSign == 0)
+            AddEqCase(Builder.CreateNot(Builder.CreateOr(A, B)));
+          // only B true (sum == ValB)
+          if (CSign == ValB) {
+            Value *NotA = Builder.CreateNot(A);
+            AddEqCase(Builder.CreateAnd(NotA, B));
+          }
+          // only A true (sum == ValA)
+          if (CSign == ValA) {
+            Value *NotB = Builder.CreateNot(B);
+            AddEqCase(Builder.CreateAnd(A, NotB));
+          }
+          // both true (sum == ValA + ValB)
+          if (CSign == ValA + ValB)
+            AddEqCase(Builder.CreateAnd(A, B));
+
+          if (EqResult)
+            Result = Builder.CreateNot(EqResult);
+          else
+            Result = Builder.getTrue(); // C doesn't match any possible sum
+        } else {
+          // eq C
+          auto AddEqCase = [&](Value *Cond) {
+            if (!Result)
+              Result = Cond;
+            else
+              Result = Builder.CreateOr(Result, Cond);
+          };
+          // both false (sum == 0)
+          if (CSign == 0)
+            AddEqCase(Builder.CreateNot(Builder.CreateOr(A, B)));
+          // only B true (sum == ValB)
+          if (CSign == ValB) {
+            Value *NotA = Builder.CreateNot(A);
+            AddEqCase(Builder.CreateAnd(NotA, B));
+          }
+          // only A true (sum == ValA)
+          if (CSign == ValA) {
+            Value *NotB = Builder.CreateNot(B);
+            AddEqCase(Builder.CreateAnd(A, NotB));
+          }
+          // both true (sum == ValA + ValB)
+          if (CSign == ValA + ValB)
+            AddEqCase(Builder.CreateAnd(A, B));
+
+          if (!Result)
+            Result = Builder.getFalse(); // C doesn't match any possible sum
+        }
+
+        return replaceInstUsesWith(Cmp, Result);
+      }
+    }
     break;
   }
   case Instruction::Xor:

